mapper.select:
select s.id, s.name, s.no, s.gender, s.phone, s.degree, s.id_card as idCard, s.is_college as isCollege, s.address, s.graduation_date as graduationDate, s.violation_count as violationCount, s.violation_score as violationScore, s.clazz_id as clazzId, c.name as clazzName, s.create_time as createTime, s.update_time as updateTime from student s left join clazz c on s.clazz_id = c.id
and s.name like concat('%', #{name}, '%')
and s.degree = #{degree}
and s.clazz_id = #{clazzId}
order by s.update_time desc

mapper.update:
update student
no = #{no}, name = #{name}, gender = #{gender}, phone = #{phone}, degree = #{degree}, is_college = #{isCollege}, id_card = #{idCard}, address = #{address}, graduation_date = #{graduationDate }, violation_count = #{violationCount}, violation_score = #{violationScore}, clazz_id = #{clazzId},
where id = #{id}
